int a[N], ans[N];
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 1, n)ans[i] = INF;

	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n) {
		if (i - a[i] >= 1) {
			int j = i - a[i];
			g[j].pb(i);
			if (a[j] % 2 != a[i] % 2)ans[i] = 1;
		}
		if (i + a[i] <= n) {
			int j = i + a[i];
			g[j].pb(i);
			if (a[j] % 2 != a[i] % 2)ans[i] = 1;
		}
	}

	var Q = queue<int>();
	fa(i, 1, n)if (ans[i] == 1)Q.push(i);
	while (Q.size()) {
		int now = Q.front();
		Q.pop();
		for (int to : g[now]) {
			if (ans[to] > ans[now] + 1) {
				ans[to] = ans[now] + 1;
				Q.push(to);
			}
		}
	}

	fa(i, 1, n) {
		if (ans[i] >= INF)cout << -1 << ' ';
		else cout << ans[i] << ' ';
	}
	cout << endl;
	return;
}
